def write_js(filename, data, var_name, comment):
    body = json.dumps(data, ensure_ascii=False, indent=2)
    js = f"/* {comment} */\n(function (root, factory) {{\n  if (typeof module === 'object' && module.exports) module.exports = factory();\n  else root.{var_name} = factory();\n}}(typeof self !== 'undefined' ? self : this, function () {{\n  return {body};\n}}));\n"
    (root/'data'/filename).write_text(js, encoding='utf-8')

write_js('paddles.js', paddles, 'SITE_PADDLES', 'Enriched paddle database. Prices are USD reference prices from official/source pages and should be verified before publishing purchase advice.')
write_js('players.js', players, 'SITE_PLAYERS', 'Enriched pro player profiles. Rankings, DUPR, sponsors, and images should be checked against live official profiles before publication.')

